    "voice_pack_clean_title": "ಸ್ವಚ್ಛವಾದ ಮಿಶ್ರಣಕ್ಕಾಗಿ, ಪ್ರತಿ ರೆಕಾರ್ಡಿಂಗ್ ನಂತರ ಮೌನವನ್ನು ಕತ್ತರಿಸಿ ಮತ್ತು ಧ್ವನಿ ಮಟ್ಟವನ್ನು ಸಮಗೊಳಿಸಿ",
    "voice_pack_clean": "ಸ್ವಯಂ-ಕತ್ತರಿಸಿ ಮತ್ತು ಮಟ್ಟ ಮಾಡಿ",
    "voice_pack_aicheck_title": "ಕೋಚ್: ಪ್ರತಿ ಕ್ಲಿಪ್ ಅನ್ನು ಗುರಿ ಧ್ವನಿಯ ವಿರುದ್ಧ ತೀರ್ಮಾನಿಸುತ್ತದೆ (ಅದನ್ನು Gemini ಗೆ ಕಳುಹಿಸುತ್ತದೆ)",
    "voice_pack_aicheck_needs_canvas": "AI ಕೋಚ್‌ಗೆ Canvas ಬೇಕು",
    "voice_pack_aicheck": "AI ಕೋಚ್",
    "voice_pack_aicheck_note": "ಪ್ರತಿ ಕ್ಲಿಪ್ ಅನ್ನು ವಿಶ್ಲೇಷಣೆಗಾಗಿ Gemini ಗೆ ಕಳುಹಿಸಲಾಗುತ್ತದೆ.",
    "voice_pack_intro_student": "ವಿದ್ಯಾರ್ಥಿಯು ಪ್ರತಿ ಧ್ವನಿಯನ್ನು ತಮ್ಮ ಸ್ವಂತ ಧ್ವನಿಯಲ್ಲಿ ರೆಕಾರ್ಡ್ ಮಾಡುತ್ತಾರೆ (ಮಾಲೀಕತ್ವ ಮತ್ತು ಉಚ್ಚಾರಣಾ ಅಭ್ಯಾಸಕ್ಕೆ ಉತ್ತಮ). ಮೊದಲು ಮಾದರಿಯನ್ನು ಕೇಳಲು 👂 ಟ್ಯಾಪ್ ಮಾಡಿ, ನಂತರ ರೆಕಾರ್ಡ್ ಮಾಡಲು 🎙️. ವಿದ್ಯಾರ್ಥಿ ಧ್ವನಿ ಒಂದು ಗೌಪ್ಯ ದಾಖಲೆ: ಅದು ಈ ಸಾಧನದಲ್ಲೇ ಉಳಿಯುತ್ತದೆ, ಮತ್ತು Export ನೀವು ನಿಯಂತ್ರಿಸುವ ಒಂದು ಗೌಪ್ಯ ಫೈಲ್ ಅನ್ನು ರಚಿಸುತ್ತದೆ.",
    "voice_pack_intro": "ಪ್ರತಿ ಧ್ವನಿಯನ್ನು ನಿಮ್ಮ ಸ್ವಂತ ಧ್ವನಿಯಲ್ಲಿ ರೆಕಾರ್ಡ್ ಮಾಡಿ: ಮಾದರಿಯನ್ನು ಕೇಳಲು 👂 ಟ್ಯಾಪ್ ಮಾಡಿ, ನಂತರ 🎙️ ಮತ್ತು ಧ್ವನಿಯನ್ನು ಮೊಟಕಾಗಿ ಹೇಳಿ (\"/p/\", \"puh\" ಅಲ್ಲ). ಮಿಶ್ರಣ, ಪ್ರತ್ಯೇಕೀಕರಣ ಮತ್ತು ಆ್ಯಂಕರ್ ಕಾರ್ಡ್ ಸಮಯದಲ್ಲಿ ಆ್ಯಪ್ ನಿಮ್ಮ ಧ್ವನಿಯನ್ನು ಪ್ಲೇ ಮಾಡುತ್ತದೆ. ಖಾಲಿ ಧ್ವನಿಗಳು ಡೀಫಾಲ್ಟ್ ಧ್ವನಿಯನ್ನು ಉಳಿಸಿಕೊಳ್ಳುತ್ತವೆ.",
    "voice_pack_consent_title": "ವಿದ್ಯಾರ್ಥಿಯ ಧ್ವನಿಯನ್ನು ರೆಕಾರ್ಡ್ ಮಾಡುವುದು",
    "voice_pack_consent_body": "ವಿದ್ಯಾರ್ಥಿಯ ಧ್ವನಿ ರೆಕಾರ್ಡಿಂಗ್ ಒಂದು ಗೌಪ್ಯ, ಬಯೋಮೆಟ್ರಿಕ್-ಸದೃಶ ದಾಖಲೆ. ಅದು ಈ ಸಾಧನದಲ್ಲೇ ಉಳಿಯುತ್ತದೆ, ಈ ಸಾಧನದಿಂದ ಎಂದಿಗೂ ಅಪ್‌ಲೋಡ್ ಆಗುವುದಿಲ್ಲ (ನೀವು AI ಪರಿಶೀಲನೆಯನ್ನು ಆನ್ ಮಾಡಿದರೆ, ಅದು ಮಾತ್ರ ಒಂದು ಕ್ಲಿಪ್ ಅನ್ನು ಹೊರಗೆ ಕಳುಹಿಸುತ್ತದೆ), ಮತ್ತು ನೀವು ಅದನ್ನು ಯಾವಾಗ ಬೇಕಾದರೂ ಅಳಿಸಬಹುದು. ಈ ವಿದ್ಯಾರ್ಥಿಯನ್ನು ರೆಕಾರ್ಡ್ ಮಾಡಲು ನಿಮಗೆ ಅನುಮತಿ ಇದೆ ಎಂದು ದೃಢೀಕರಿಸಿ.",
    "voice_pack_consent_ok": "ನನಗೆ ಅನುಮತಿ ಇದೆ, ರೆಕಾರ್ಡಿಂಗ್ ಪ್ರಾರಂಭಿಸಿ",
    "voice_pack_tab_record": "ರೆಕಾರ್ಡ್",
    "voice_pack_tab_progress": "ಪ್ರಗತಿ",
    "voice_pack_progress_empty": "ಇಲ್ಲಿ ಅಭ್ಯಾಸ ಲಾಗ್ ರಚಿಸಲು ಧ್ವನಿಗಳನ್ನು ರೆಕಾರ್ಡ್ ಮಾಡಿ (😀 / 🤔 ಸ್ವಯಂ-ಮೌಲ್ಯಮಾಪನದೊಂದಿಗೆ, ಅಥವಾ 🎯 AI ಕೋಚ್ ಆನ್ ಮಾಡಿ). ಪ್ರತಿ ರೆಕಾರ್ಡಿಂಗ್ ಲಾಗ್ ಆಗುತ್ತದೆ, ಇದರಿಂದ ಒಂದು ಧ್ವನಿ ಕಾಲಾನುಕ್ರಮದಲ್ಲಿ ಸುಧಾರಿಸುವುದನ್ನು ನೀವು ನೋಡಬಹುದು.",
