      "for_n_variables_the_table_has_2_rows_a": "n ಚರಗಳಿಗೆ, ಕೋಷ್ಟಕದಲ್ಲಿ 2ⁿ ಸಾಲುಗಳಿರುತ್ತವೆ. AND, OR, NOT, XOR, IFF — ಪ್ರತಿ ಗೇಟ್ ಕೇವಲ ಒಂದು ಕಾಲಮ್. ಬೂಲಿಯನ್ ಬೀಜಗಣಿತ (ಬೂಲ್, 1854) ಪ್ರತಿ ಡಿಜಿಟಲ್ ಸರ್ಕ್ಯೂಟ್, ಪ್ರತಿ ಹುಡುಕಾಟ ಪ್ರಶ್ನೆ ಮತ್ತು ಕೋಡ್‌ನಲ್ಲಿ ಪ್ರತಿ ಷರತ್ತಿನ ಆಧಾರ.",
      "proof_builder_derive_conclusions_step_": "ಸಾಬೀತು ನಿರ್ಮಾಪಕ — ಹಂತ-ಹಂತವಾಗಿ ತೀರ್ಮಾನಗಳನ್ನು ಪಡೆಯಿರಿ",
      "modus_ponens_modus_tollens_hypothetica": "Modus ponens, modus tollens, ಊಹಾತ್ಮಕ ನ್ಯಾಯ, ವಿಯೋಜಕ ನ್ಯಾಯ — ಎಂಟು ನಿಗಮನ ನಿಯಮಗಳು ಬಹುತೇಕ ಪ್ರಾರಂಭಿಕ ಪ್ರತಿಪಾದನಾ ತರ್ಕವನ್ನು ಒಳಗೊಳ್ಳುತ್ತವೆ. ಪ್ರತಿ ಹಂತವು ಭಾವನೆಯಿಂದಲ್ಲ, ಹೆಸರಿನಿಂದ ತನ್ನನ್ನು ಸಮರ್ಥಿಸಿಕೊಳ್ಳುತ್ತದೆ.",
      "challenges_graded_tautology_contradict": "ಸವಾಲುಗಳು — ಶ್ರೇಣೀಕೃತ ಸ್ವತಃಸತ್ಯ ಮತ್ತು ವಿರೋಧಾಭಾಸ ಒಗಟುಗಳು",
      "tautology_always_true_contradiction_al": "ಸ್ವತಃಸತ್ಯ = ಯಾವಾಗಲೂ ಸತ್ಯ; ವಿರೋಧಾಭಾಸ = ಯಾವಾಗಲೂ ಸುಳ್ಳು; ಆಕಸ್ಮಿಕತೆ = ಕೆಲವೊಮ್ಮೆ ಎರಡೂ. ಅರಿಸ್ಟಾಟಲ್‌ನ ಅವಿರೋಧ ನಿಯಮ (ಕ್ರಿ.ಪೂ. 350) ಪ್ರಕಟಿತ ಅತ್ಯಂತ ಹಳೆಯ ನಿಯಮ. AP CS Principles ಅಭ್ಯಾಸ + ವಿವಿಕ್ತ ಗಣಿತ ಪರಿಚಯ.",
      "logic_gates_transistors_all_the_way_do": "ತರ್ಕ ಗೇಟ್‌ಗಳು — ಕೆಳಗಿನವರೆಗೆ ಟ್ರಾನ್ಸಿಸ್ಟರ್‌ಗಳು",
      "nand_is_functionally_complete_you_can_": "NAND ಕ್ರಿಯಾತ್ಮಕವಾಗಿ ಪೂರ್ಣ — ನೀವು NAND ನಿಂದ ಮಾತ್ರ ಪ್ರತಿ ಇತರ ಗೇಟ್ ಅನ್ನು ನಿರ್ಮಿಸಬಹುದು. ಆಧುನಿಕ CPU ನಲ್ಲಿ ಸುಮಾರು 10 ಬಿಲಿಯನ್ ಟ್ರಾನ್ಸಿಸ್ಟರ್‌ಗಳಿರುತ್ತವೆ, ಅವು ನೀವು ಇಲ್ಲಿ ನಿರ್ಮಿಸುತ್ತಿರುವ ಅದೇ ಬೂಲಿಯನ್ ಗಣಿತವನ್ನು ಅನುಷ್ಠಾನಗೊಳಿಸುತ್ತವೆ.",
      "probability_logic_inference_under_unce": "ಸಂಭವನೀಯತೆ ತರ್ಕ — ಅನಿಶ್ಚಿತತೆಯಲ್ಲಿ ನಿಗಮನ",
      "p_and_q_each_carry_a_probability_inste": "P ಮತ್ತು Q ಪ್ರತಿಯೊಂದೂ ಕಠಿಣ ಸತ್ಯ/ಸುಳ್ಳಿನ ಬದಲಿಗೆ ಒಂದು ಸಂಭವನೀಯತೆಯನ್ನು ಹೊಂದಿರುತ್ತವೆ. ಸ್ವತಂತ್ರ ಘಟನೆಗಳಿಗೆ, P(P∧Q) = P(P) × P(Q). ವಿಶ್ವಾಸ ಮಿತಿಯು ಮೃದು ಸಂಭವನೀಯತೆಗಳನ್ನು ವಿವಿಕ್ತ ನಿಗಮನಗಳಾಗಿ ಹೇಗೆ ಪರಿವರ್ತಿಸುತ್ತದೆ ಎಂಬುದನ್ನು ಗಮನಿಸಿ.",
