      "stopovers_are_not_just_rest_stops_they": "ನಿಲುಗಡೆ ಸ್ಥಳಗಳು ಕೇವಲ ವಿಶ್ರಾಂತಿ ಸ್ಥಳಗಳಲ್ಲ, ಅವು ",
      "refueling_stations": "ಇಂಧನ-ತುಂಬುವ ನಿಲ್ದಾಣಗಳು",
      "critical_to_survival_a_migrating_warbl": " ಆಗಿದ್ದು ಬದುಕುಳಿಯುವಿಕೆಗೆ ನಿರ್ಣಾಯಕ. ಒಂದು ವಲಸೆ ವಾರ್ಬ್ಲರ್ ವಲಸೆ ಸಮಯದ 75% ಅನ್ನು ನಿಲುಗಡೆ ಸ್ಥಳಗಳಲ್ಲಿ ಕಳೆಯಬಹುದು, ಕೊಬ್ಬಿನ ಸಂಗ್ರಹವನ್ನು ಮರುನಿರ್ಮಿಸಲು ಹುಚ್ಚುಚ್ಚಾಗಿ ತಿನ್ನುತ್ತಾ. ಗುಣಮಟ್ಟದ ನಿಲುಗಡೆ-ಸ್ಥಳ ಆವಾಸ ಜೀವನ ಮತ್ತು ಮರಣದ ನಡುವಿನ ವ್ಯತ್ಯಾಸವಾಗಬಹುದು.",
      "at_delaware_bay_over_1_million_shorebi": "Delaware Bay ನಲ್ಲಿ, 10 ಲಕ್ಷಕ್ಕೂ ಹೆಚ್ಚು ಕರಾವಳಿ ಹಕ್ಕಿಗಳು (Red Knots, Ruddy Turnstones, Sanderlings) ಮೇ ತಿಂಗಳಲ್ಲಿ ಇಡುವ ಕುದುರೆ-ಲಾಳ ಏಡಿ ಮೊಟ್ಟೆಗಳನ್ನು ಅವಲಂಬಿಸಿವೆ. ಸಮಯ ಪರಿಪೂರ್ಣವಾಗಿರಬೇಕು: ಕುದುರೆ-ಲಾಳ ಏಡಿಗಳು ಮೊಟ್ಟೆ ಇಡುವ ನಿಖರವಾಗಿ ಆ ಸಮಯದಲ್ಲಿ ಹಕ್ಕಿಗಳು ಬರುತ್ತವೆ. ಕುದುರೆ-ಲಾಳ ಏಡಿಗಳ ಜನಸಂಖ್ಯೆ ಕಡಿಮೆಯಾದರೆ (ಬೆಟ್‌ಗಾಗಿ ಅತಿಯಾದ ಮೀನುಗಾರಿಕೆಯಿಂದ), ಇಡೀ ವಲಸೆ ಸರಪಳಿ ಕುಸಿಯುತ್ತದೆ.",
      "conservation_success_story_after_horse": "ಸಂರಕ್ಷಣಾ ಯಶೋಗಾಥೆ: 2012 ರಲ್ಲಿ ಕುದುರೆ-ಲಾಳ ಏಡಿ ಕೊಯ್ಲು ಮಿತಿಗಳನ್ನು ಪರಿಚಯಿಸಿದ ನಂತರ, Red Knot ಜನಸಂಖ್ಯೆ ಬಿಕ್ಕಟ್ಟಿನ ಕನಿಷ್ಠ 15,000 ರಿಂದ 2025 ರ ವೇಳೆಗೆ 50,000 ಕ್ಕೂ ಹೆಚ್ಚಕ್ಕೆ ನಿಧಾನವಾಗಿ ಚೇತರಿಸಿಕೊಳ್ಳಲು ಪ್ರಾರಂಭಿಸಿತು.",
      "migration_physiology": "🦴 ವಲಸೆ ಶರೀರಶಾಸ್ತ್ರ",
      "migration_is_one_of_the_most_physicall": "ವಲಸೆ ಪ್ರಾಣಿ ಸಾಮ್ರಾಜ್ಯದಲ್ಲಿ ದೈಹಿಕವಾಗಿ ಅತ್ಯಂತ ಬೇಡಿಕೆಯ ಚಟುವಟಿಕೆಗಳಲ್ಲಿ ಒಂದು. ಹಕ್ಕಿಗಳು ಹೊರಡುವ ಮೊದಲು ಆಶ್ಚರ್ಯಕರ ಶಾರೀರಿಕ ರೂಪಾಂತರಗಳಿಗೆ ಒಳಗಾಗುತ್ತವೆ:",
      "hyperphagia": "ಅತಿಭಕ್ಷಣೆ",
      "before_migration_birds_enter_a_feeding": "ವಲಸೆ ಮೊದಲು, ಹಕ್ಕಿಗಳು ಅತಿಭಕ್ಷಣೆ ಎಂಬ ಆಹಾರ ಉನ್ಮಾದಕ್ಕೆ ಪ್ರವೇಶಿಸುತ್ತವೆ, ಸಾಮಾನ್ಯಕ್ಕಿಂತ 2-3 ಪಟ್ಟು ವೇಗದಲ್ಲಿ ಆಹಾರ ಸೇವಿಸುತ್ತವೆ. Blackpoll Warbler (12 ಗ್ರಾಂ) 8-12 ಗ್ರಾಂ ಕೊಬ್ಬಿನ ಸಂಗ್ರಹ ಸೇರಿಸುತ್ತದೆ, ದೇಹದ ತೂಕವನ್ನು ಬಹುತೇಕ ದ್ವಿಗುಣಗೊಳಿಸುತ್ತದೆ. ಈ ಕೊಬ್ಬು 2,000 ಮೈಲಿಗಿಂತ ಹೆಚ್ಚಿನ ನಿರಂತರ ಹಾರಾಟಗಳಿಗೆ ಇಂಧನ.",
      "organ_shrinkage": "ಅಂಗ ಕುಗ್ಗುವಿಕೆ",
      "to_reduce_weight_migrating_birds_actua": "ತೂಕ ಕಡಿಮೆ ಮಾಡಲು, ವಲಸೆ ಹಕ್ಕಿಗಳು ಹೊರಡುವ ಮೊದಲು ಜೀರ್ಣಕ್ರಿಯೆ ಅಂಗಗಳನ್ನು (ಕರುಳು, ಯಕೃತ್ತು, ಜಠರ) ನಿಜವಾಗಿ 40% ವರೆಗೆ ಕುಗ್ಗಿಸುತ್ತವೆ. ನಿಲುಗಡೆ ಸ್ಥಳಗಳಿಗೆ ಬಂದಾಗ, ಅವು ಇಂಧನ ತುಂಬಲು ಈ ಅಂಗಗಳನ್ನು ವೇಗವಾಗಿ ಮರುನಿರ್ಮಿಸುತ್ತವೆ. ಈ “ಸ್ವರೂಪ ನಮ್ಯತೆ” ಕಶೇರುಕಗಳಲ್ಲಿ ವಿಶಿಷ್ಟ.",
      "hemoglobin": "ಹಿಮೋಗ್ಲೋಬಿನ್",
      "high_altitude_migrants_like_bar_headed": "Bar-headed Geese (ಹಿಮಾಲಯದ ಮೇಲೆ 29,000 ಅಡಿಗಳಲ್ಲಿ ಹಾರುವ) ನಂತಹ ಉನ್ನತ-ಎತ್ತರದ ವಲಸೆ ಹಕ್ಕಿಗಳು, ಆಮ್ಲಜನಕಕ್ಕೆ ಹೆಚ್ಚಿನ ಆಕರ್ಷಣೆ ಹೊಂದಿರುವ ವಿಶೇಷ ಹಿಮೋಗ್ಲೋಬಿನ್ ಹೊಂದಿವೆ. ಅವುಗಳ ಸ್ನಾಯುಗಳಲ್ಲಿ ಹೆಚ್ಚುವರಿ ಮಯೋಗ್ಲೋಬಿನ್ ಇದೆ, ಮತ್ತು ಅವುಗಳ ಕ್ಯಾಪಿಲರಿ ಸಾಂದ್ರತೆ ತಗ್ಗು ಪ್ರದೇಶದ ಪ್ರಭೇದಗಳಿಗಿಂತ ಎರಡು ಪಟ್ಟು.",
      "sleep_in_flight": "ಹಾರಾಟದಲ್ಲಿ ನಿದ್ರೆ",
      "some_birds_can_sleep_while_flying_usin": "ಕೆಲವು ಹಕ್ಕಿಗಳು ಹಾರುತ್ತಲೇ ನಿದ್ರಿಸಬಲ್ಲವು, “ಅರ್ಧ-ಗೋಳಾರ್ಧ ನಿದ್ರೆ”ಯನ್ನು ಬಳಸಿ — ಒಂದೇ ಸಮಯದಲ್ಲಿ ಮೆದುಳಿನ ಒಂದು ಗೋಳಾರ್ಧವನ್ನು ಮುಚ್ಚಿ. ಫ್ರಿಗೇಟ್‌ಬರ್ಡ್‌ಗಳು 10-ದಿನಗಳ ಸಾಗರ-ದಾಟುವ ಹಾರಾಟಗಳ ಸಮಯದಲ್ಲಿ ದಿನಕ್ಕೆ 42 ನಿಮಿಷ ನಿದ್ರಿಸುವುದಾಗಿ ದಾಖಲಾಗಿದೆ, ಪ್ರತಿಯೊಂದೂ 12 ಸೆಕೆಂಡ್ ಸೂಕ್ಷ್ಮ-ನಿದ್ರೆಗಳನ್ನು ತೆಗೆದುಕೊಳ್ಳುತ್ತಾ.",
      "navigation_clock": "ಸಂಚಾರ ಗಡಿಯಾರ",
      "birds_maintain_an_internal_circadian_c": "ಹಕ್ಕಿಗಳು ಅಸಾಧಾರಣ ನಿಖರತೆಯ ಆಂತರಿಕ ಸಿರ್ಕಾಡಿಯನ್ ಗಡಿಯಾರವನ್ನು ನಿರ್ವಹಿಸುತ್ತವೆ. ಈ ಗಡಿಯಾರ ಆಕಾಶದಲ್ಲಿ ಸೂರ್ಯನ ಚಲನೆಯನ್ನು ಸರಿದೂಗಿಸುತ್ತದೆ (ಸಮಯ-ಸರಿದೂಗಿಸಿದ ಸೌರ ದಿಕ್ಸೂಚಿ) ಮತ್ತು ವಲಸೆ ಹಾರ್ಮೋನ್‌ಗಳನ್ನು ಪ್ರಚೋದಿಸುವ ಹಗಲಿನ ಉದ್ದದ ಋತುಮಾನ ಬದಲಾವಣೆಗಳನ್ನು ಟ್ರ್ಯಾಕ್ ಮಾಡುತ್ತದೆ.",
      "zugunruhe": "Zugunruhe",
      "zugunruhe_migration_restlessness_is_a_": "Zugunruhe (“ವಲಸೆ ಚಡಪಡಿಕೆ”) ಒಂದು ವರ್ತನೆ ಸ್ಥಿತಿ, ಇದರಲ್ಲಿ ಪಂಜರದಲ್ಲಿ ಬಂಧಿಸಲ್ಪಟ್ಟ ವಲಸೆ ಹಕ್ಕಿಗಳು ಅವು ಸ್ವಾಭಾವಿಕವಾಗಿ ವಲಸೆ ಹೋಗುವ ದಿಕ್ಕಿನಲ್ಲಿ, ಅವು ವಲಸೆ ಹೋಗುವ ಸಮಯದಲ್ಲಿ ರೆಕ್ಕೆ ಬಡಿಯುತ್ತವೆ. ಇದು ಹಾರ್ಮೋನ್-ಚಾಲಿತ ಮತ್ತು ಆನುವಂಶಿಕವಾಗಿ ಸಂಕೇತಿಸಲ್ಪಟ್ಟಿದೆ. ವಲಸೆ ಅನುಭವವಿಲ್ಲದ, ಕೈಯಿಂದ ಬೆಳೆಸಿದ ಹಕ್ಕಿಗಳೂ Zugunruhe ತೋರಿಸುತ್ತವೆ.",
      "species_comparison": "📊 ಪ್ರಭೇದ ಹೋಲಿಕೆ",
      "canada_goose": "Canada Goose",
      "3_000_ft": "3,000 ft",
