      "gas_exchange": "ಅನಿಲ ವಿನಿಮಯ",
      "the_circulatory_system_delivers_deoxyg": "ರಕ್ತಪರಿಚಲನಾ ವ್ಯವಸ್ಥೆ ಆಮ್ಲಜನಕರಹಿತ ರಕ್ತವನ್ನು ಶ್ವಾಸಕೋಶಗಳಿಗೆ ತಲುಪಿಸುತ್ತದೆ, ಅಲ್ಲಿ ಉಸಿರಾಟದ ವ್ಯವಸ್ಥೆ ಅದನ್ನು ಆಮ್ಲಜನಕದಿಂದ ತುಂಬಿಸಿ, ತೆಳುವಾದ ವಾಯುಕೋಶ-ಕೇಶನಾಳ ಪೊರೆಯ ಮೂಲಕ ಇಂಗಾಲದ ಡೈಆಕ್ಸೈಡ್ ಅನ್ನು ಬಿಡುಗಡೆ ಮಾಡುತ್ತದೆ.",
      "neuromuscular_junction": "ನರ-ಸ್ನಾಯು ಸಂಧಿ",
      "motor_neurons_from_the_nervous_system_": "ನರವ್ಯವಸ್ಥೆಯಿಂದ ಚಲನ ನರಕೋಶಗಳು ನರ-ಸ್ನಾಯು ಸಂಧಿಯಲ್ಲಿ ಅಸಿಟೈಲ್‌ಕೋಲಿನ್ ಬಿಡುಗಡೆ ಮಾಡಿ ಸ್ನಾಯುತಂತು ಸಂಕೋಚನವನ್ನು ಪ್ರಚೋದಿಸುತ್ತವೆ. ನರ ಸಂಕೇತಗಳಿಲ್ಲದೆ ಸ್ನಾಯುಗಳು ಚಲಿಸಲಾರವು.",
      "lever_system_for_movement": "ಚಲನೆಗಾಗಿ ಸನ್ನೆ ವ್ಯವಸ್ಥೆ",
      "muscles_attach_to_bones_via_tendons_an": "ಸ್ನಾಯುಗಳು ಸ್ನಾಯುರಜ್ಜುಗಳ ಮೂಲಕ ಮೂಳೆಗಳಿಗೆ ಜೋಡಿಸಿಕೊಂಡು ಕೀಲುಗಳ ಮೇಲೆ ಎಳೆದು ಸನ್ನೆ ವ್ಯವಸ್ಥೆಗಳನ್ನು ಸೃಷ್ಟಿಸುತ್ತವೆ. ಅಸ್ಥಿಪಂಜರ ದೃಢ ಸನ್ನೆಗಳನ್ನು ಒದಗಿಸುತ್ತದೆ; ಸ್ನಾಯುಗಳು ಎಳೆಯುವ ಬಲವನ್ನು ಒದಗಿಸುತ್ತವೆ.",
      "hormonal_regulation_of_reproduction": "ಸಂತಾನೋತ್ಪತ್ತಿಯ ಹಾರ್ಮೋನ್ ನಿಯಂತ್ರಣ",
      "the_hypothalamus_pituitary_axis_releas": "ಹೈಪೋಥಲಾಮಸ್-ಪಿಟ್ಯುಟರಿ ಅಕ್ಷ FSH ಮತ್ತು LH ಅನ್ನು ಬಿಡುಗಡೆ ಮಾಡಿ ಜನನಾಂಗ ಗ್ರಂಥಿಗಳನ್ನು ನಿಯಂತ್ರಿಸುತ್ತದೆ. ಸಂತಾನೋತ್ಪತ್ತಿ ಅಂಗಗಳಿಂದ ಈಸ್ಟ್ರೊಜೆನ್, ಪ್ರೊಜೆಸ್ಟೆರಾನ್, ಟೆಸ್ಟೊಸ್ಟೆರಾನ್ ಅಂತಃಸ್ರಾವ ವ್ಯವಸ್ಥೆಗೆ ಹಿಮ್ಮಾಹಿತಿ ನೀಡುತ್ತವೆ.",
